            return 1;
        }

        printf("Login successful.\n");
        if (isAdmin) {
            printf("Admin token: %s\n", token);
            break;
        }
    }
    if (row_count == 0) {
        printf("Invalid username or password.\n");
    }

    // Finalize and clean up
    sqlite3_finalize(res);
    sqlite3_close(db);

    return 0;
}
